impl Default for AppSettings {
    fn default() -> Self {
        Self {
            version: default_settings_version(),
            // Indexing
            index_dirs: Vec::new(),
            exclude_patterns: vec![
                ".git/".to_string(),
                "node_modules/".to_string(),
                "target/".to_string(),
                "AppData/".to_string(),
                "*.tmp".to_string(),
